import React, { useState, useEffect } from "react";
import "./styles.css";
import MenuBar from "../menubar/MenuBar";
import {
  Layout,
  Menu,
  Breadcrumb,
  Typography,
  Select,
  Input,
  Table,
  Badge,
  Button,
  Avatar,
  Space,
  Flex,
} from 'antd';
import type { MenuProps, TableProps } from 'antd';
import {
  DashboardOutlined,
  DesktopOutlined,
  MessageOutlined,
  FileTextOutlined,
  SettingOutlined,
  LogoutOutlined,
  BellOutlined,
  PlusOutlined,
  SearchOutlined,
  RightOutlined,
  LeftOutlined,
} from '@ant-design/icons';

const { Header, Content, Sider } = Layout;
const { Title, Text } = Typography;
const { Option } = Select;

type MenuItem = Required<MenuProps>['items'][number];

function getItem(
  label: React.ReactNode,
  key: React.Key,
  icon?: React.ReactNode,
  children?: MenuItem[],
): MenuItem {
  return {
    key,
    icon,
    children,
    label,
  } as MenuItem;
}

const menuItems: MenuItem[] = [
  getItem('Dashboard', '1', <DashboardOutlined />),
  getItem('Thiết bị', '2', <DesktopOutlined />),
  getItem('Dịch vụ', '3', <MessageOutlined />),
  getItem('Cấp số', '4', <FileTextOutlined />),
  getItem('Báo cáo', '5', <FileTextOutlined />),
  getItem('Cài đặt hệ thống', '6', <SettingOutlined />),
];

interface DataType {
  key: string;
  maThietBi: string;
  tenThietBi: string;
  diaChiIP: string;
  trangThaiHoatDong: 'Hoạt động' | 'Ngưng hoạt động';
  trangThaiKetNoi: 'Kết nối' | 'Mất kết nối';
  dichVuSuDung: string;
}

const dataSource: DataType[] = [
  { key: '1', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '2', maThietBi: 'KIO_02', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.11', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '3', maThietBi: 'KIO_03', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.12', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '4', maThietBi: 'KIO_04', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.13', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '5', maThietBi: 'KIO_05', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.14', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '6', maThietBi: 'KIO_06', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.15', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '7', maThietBi: 'KIO_07', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.16', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '8', maThietBi: 'KIO_08', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.17', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '9', maThietBi: 'KIO_09', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.18', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
];

const Device: React.FC = () => {
  // Filters state
  const [activityFilter, setActivityFilter] = useState<string>('Tất cả');
  const [connectionFilter, setConnectionFilter] = useState<string>('Tất cả');
  const [keyword, setKeyword] = useState<string>('');

  // Filtered data shown in the table
  const [filteredData, setFilteredData] = useState<DataType[]>(dataSource);

  // handleFilter uses `switch` as requested and updates filteredData
  const handleFilter = (
    act: string = activityFilter,
    conn: string = connectionFilter,
    key: string = keyword,
  ) => {
    const trimmedKey = key?.trim().toLowerCase() || '';

    const result = dataSource.filter(item => {
      // activity match
      let matchAct = true;
      switch (act) {
        case 'Hoạt động':
          matchAct = item.trangThaiHoatDong === 'Hoạt động';
          break;
        case 'Ngưng hoạt động':
          matchAct = item.trangThaiHoatDong === 'Ngưng hoạt động';
          break;
        default:
          matchAct = true; // 'Tất cả' or unknown -> pass
      }

      // connection match
      let matchConn = true;
      switch (conn) {
        case 'Kết nối':
          matchConn = item.trangThaiKetNoi === 'Kết nối';
          break;
        case 'Mất kết nối':
          matchConn = item.trangThaiKetNoi === 'Mất kết nối';
          break;
        default:
          matchConn = true;
      }

      // keyword match (search in several fields)
      let matchKey = true;
      if (trimmedKey.length > 0) {
        const hay = `${item.maThietBi} ${item.tenThietBi} ${item.diaChiIP} ${item.dichVuSuDung}`.toLowerCase();
        matchKey = hay.includes(trimmedKey);
      }

      return matchAct && matchConn && matchKey;
    });

    setFilteredData(result);
  };

  // Re-run filter whenever any filter state changes
  useEffect(() => {
    handleFilter(activityFilter, connectionFilter, keyword);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activityFilter, connectionFilter, keyword]);

  const columns: TableProps<DataType>['columns'] = [
    { title: 'Mã thiết bị', dataIndex: 'maThietBi', key: 'maThietBi' },
    { title: 'Tên thiết bị', dataIndex: 'tenThietBi', key: 'tenThietBi' },
    { title: 'Địa chỉ IP', dataIndex: 'diaChiIP', key: 'diaChiIP' },
    {
      title: 'Trạng thái hoạt động',
      dataIndex: 'trangThaiHoatDong',
      key: 'trangThaiHoatDong',
      render: (text: any) => (
        <Badge
          status={text === 'Hoạt động' ? 'success' : 'error'}
          text={text}
        />
      ),
    },
    {
      title: 'Trạng thái kết nối',
      dataIndex: 'trangThaiKetNoi',
      key: 'trangThaiKetNoi',
      render: (text: any) => (
        <Badge
          status={text === 'Kết nối' ? 'success' : 'error'}
          text={text}
        />
      ),
    },
    {
      title: 'Dịch vụ sử dụng',
      dataIndex: 'dichVuSuDung',
      key: 'dichVuSuDung',
      render: (text: any) => (
        <div>
          {text}
          <br />
          <a href="services.tsx">Xem thêm</a>
        </div>
      ),
      width: 250,
    },
    {
      title: '',
      key: 'actionDetail',
      render: () => <a href="service_detail.tsx">Chi tiết</a>,
    },
    {
      title: '',
      key: 'actionUpdate',
      render: () => <a href="service_update.tsx">Cập nhật</a>,
    },
  ];

  return (
    <Layout style={{ minHeight: '100vh', backgroundColor: '#F6F6F6' }}>
      <Sider width={200} className="sider-custom">
        <div className="logo">
          <img src={`${process.env.PUBLIC_URL}/images/alta-logo.png`} alt="Alta Media" />
        </div>
        <Menu
          mode="vertical"
          defaultSelectedKeys={['2']}
          items={menuItems}
          className="sider-menu"
        />
        <Button className="logout-button" icon={<LogoutOutlined />} 
          onClick={()=>{
            localStorage.clear();
            window.location.reload();
          }}
        >
          Đăng xuất
        </Button>
      </Sider>

      <Layout>
        <Header className="header-custom">
          <Flex justify="space-between" align="center">
            <Breadcrumb separator={<RightOutlined style={{ fontSize: '12px', color: '#7E7D88' }} />}>
              <Breadcrumb.Item>Thiết bị</Breadcrumb.Item>
              <Breadcrumb.Item className="breadcrumb-active">Danh sách thiết bị</Breadcrumb.Item>
            </Breadcrumb>
            <Space size="large" align="center">
              <BellOutlined style={{ fontSize: '20px', color: '#FF9138' }} />
              <Space>
                <Avatar src="https://i.pravatar.cc/32" />
                <div>
                  <Text style={{ fontSize: '12px', color: '#7E7D88' }}>Xin chào</Text>
                  <br />
                  <Text strong>Lê Quỳnh Ái Vân</Text>
                </div>
              </Space>
            </Space>
          </Flex>
        </Header>

        <Content className="content-custom">
          <Title level={2} className="page-title">Danh sách thiết bị</Title>

          <Flex gap="large" align="flex-start">
            <div style={{ flex: 1 }}>
              <Flex justify="space-between" align="flex-start" style={{ marginBottom: 16 }}>
                <Space size="large">
                  <div>
                    <Text>Trạng thái hoạt động</Text>
                    <Select
                      value={activityFilter}
                      onChange={(value) => setActivityFilter(value)}
                      style={{ width: 300, display: 'block' }}
                    >
                      <Option value="Tất cả">Tất cả</Option>
                      <Option value="Hoạt động">Hoạt động</Option>
                      <Option value="Ngưng hoạt động">Ngưng hoạt động</Option>
                    </Select>
                  </div>

                  <div>
                    <Text>Trạng thái kết nối</Text>
                    <Select
                      value={connectionFilter}
                      onChange={(value) => setConnectionFilter(value)}
                      style={{ width: 300, display: 'block' }}
                    >
                      <Option value="Tất cả">Tất cả</Option>
                      <Option value="Kết nối">Kết nối</Option>
                      <Option value="Mất kết nối">Mất kết nối</Option>
                    </Select>
                  </div>
                </Space>

                <div>
                  <Text>Từ khoá</Text>
                  <Input
                    placeholder="Nhập từ khóa"
                    suffix={<SearchOutlined style={{ color: '#FF9138' }} />}
                    style={{ width: 400, display: 'block' }}
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    onPressEnter={() => handleFilter(activityFilter, connectionFilter, keyword)}
                  />
                </div>
              </Flex>

              <Table
                columns={columns}
                dataSource={filteredData}
                pagination={{
                  total: filteredData.length,
                  current: 1,
                  pageSize: 9,
                  showSizeChanger: false,
                  itemRender: (current, type, originalElement) => {
                    if (type === 'prev') {
                      return <LeftOutlined />;
                    }
                    if (type === 'next') {
                      return <RightOutlined />;
                    }
                    return originalElement;
                  },
                }}
                className="device-table"
              />
            </div>

            <Button className="add-device-button">
              <div className="add-icon-wrapper">
                <PlusOutlined />
              </div>
              Thêm thiết bị
            </Button>
          </Flex>
        </Content>
      </Layout>
    </Layout>
  );
};

export default Device;
